import { NextResponse } from 'next/server';

export async function GET(request: Request) {
  try {
    const url = new URL(request.url);
    const searchParams = url.searchParams;
    const pageParam = searchParams.get('page');

    // If no page parameter is provided, we default to the legacy behavior 
    // to avoid breaking dashboard and reports, though we could just pass default page 1 and let it run.
    // However, Dashboard expects a flat array of orders, not `{ data, metadata }`.
    // We check if `page` is present, meaning the frontend explicitly requested pagination.
    if (pageParam !== null) {
      const page = parseInt(pageParam) || 1;
      const limit = parseInt(searchParams.get('limit') || '20');
      const search = searchParams.get('search') || undefined;
      const from = searchParams.get('from') || undefined;
      const to = searchParams.get('to') || undefined;

      const paginatedOrders = await getPaginatedOrders({ search, from, to, page, limit });
      return NextResponse.json(paginatedOrders);
    }

    // Legacy support (returns all orders)
    const allOrders = await getOrders();
    return NextResponse.json(allOrders);
  } catch (error) {
    console.error('Orders API Error:', error);
    return NextResponse.json({ message: 'Failed to fetch orders' }, { status: 500 });
  }
}
import { db } from '@/db';
import { categories, items } from '@/db/schema';
import { and, eq, sql } from 'drizzle-orm';
import { unstable_cache } from 'next/cache';

// Direct query - no caching for products to ensure fresh data after mutations
export async function getProducts(params?: {
  page?: number;
  limit?: number;
  search?: string;
  categoryId?: string;
}) {
  const page = params?.page || 1;
  const limit = params?.limit || 10;
  const search = params?.search || '';
  const categoryId = params?.categoryId;
  const offset = (page - 1) * limit;

  // Base conditions
  const conditions = [eq(items.isActive, true)];

  // Search condition
  if (search) {
    const searchLower = `%${search.toLowerCase()}%`;
    conditions.push(
      sql`(${items.productName} ILIKE ${searchLower} OR ${items.barcode} ILIKE ${searchLower} OR ${items.sku} ILIKE ${searchLower})`
    );
  }

  // Category condition
  if (categoryId && categoryId !== 'ALL') {
    conditions.push(eq(items.categoryId, categoryId));
  }

  const whereClause = and(...conditions);

  // Fetch Data
  const products = await db.query.items.findMany({
    where: whereClause,
    limit: limit,
    offset: offset,
    with: {
      category: true,
    },
    orderBy: (items, { desc }) => [desc(items.createdAt)],
  });

  // Fetch Total Count for Pagination
  const countResult = await db
    .select({ count: sql<number>`count(*)` })
    .from(items)
    .where(whereClause);

  const totalItems = Number(countResult[0]?.count || 0);
  const totalPages = Math.ceil(totalItems / limit);

  return {
    data: products,
    meta: {
      page,
      limit,
      totalItems,
      totalPages,
    },
  };
}

