async function fetchCustomersOffline(search: string, outstandingOnly: boolean): Promise<CustomersPageResult> {
    const searchLower = search.trim().toLowerCase();
    const offlineCustomers = await getAllCustomers();

    const customers = offlineCustomers
        .filter(c => Boolean(c.isActive))
        .map<Customer>(c => ({
            id: c.id,
            name: c.name,
            phone: c.phone,
            cnic: c.cnic,
            address: c.address || null,
            outstandingAmount: c.outstandingAmount,
            paidAmount: c.paidAmount,
