import { db } from "@/db";
import { customers } from "@/db/schema";
import { SQL, and, asc, eq, ilike, or, sql } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const PAGE_SIZE = 20;

interface CustomerCursor {
    name: string;
    id: string;
}

interface CustomersPageResponse {
    data: (typeof customers.$inferSelect)[];
    nextCursor: string | null;
    totalCount: number;
}

function encodeCursor(cursor: CustomerCursor): string {
    return Buffer.from(JSON.stringify(cursor)).toString("base64url");
}

function decodeCursor(cursor: string | null): CustomerCursor | null {
    if (!cursor) return null;

    try {
        const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8")) as Partial<CustomerCursor>;
        if (typeof parsed.name !== "string" || typeof parsed.id !== "string") {
            return null;
        }

        return {
            name: parsed.name,
            id: parsed.id,
        };
    } catch {
        return null;
    }
}

export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const query = searchParams.get("q")?.trim() ?? "";
    const cursor = decodeCursor(searchParams.get("cursor"));
    const outstandingOnly = searchParams.get("outstanding") === "true";

    try {
        const baseConditions: SQL[] = [eq(customers.isActive, true)];

        if (query) {
            const searchPattern = `%${query}%`;
            const searchCondition = or(
                ilike(customers.name, searchPattern),
                ilike(customers.phone, searchPattern),
                ilike(customers.cnic, searchPattern)
            );

            if (searchCondition) {
                baseConditions.push(searchCondition);
            }
        }

        if (outstandingOnly) {
            baseConditions.push(sql`${customers.outstandingAmount}::numeric > 0`);
        }

        const baseWhereClause = and(...baseConditions);
        const cursorConditions = [...baseConditions];

        if (cursor) {
            const cursorCondition = or(
                sql`lower(${customers.name}) > ${cursor.name}`,
                and(
                    sql`lower(${customers.name}) = ${cursor.name}`,
                    sql`${customers.id} > ${cursor.id}`
                )
            );

            if (cursorCondition) {
                cursorConditions.push(cursorCondition);
            }
        }

        const cursorWhereClause = and(...cursorConditions);

        const [countResult, pageRows] = await Promise.all([
            db
                .select({ count: sql<number>`count(*)::int` })
                .from(customers)
                .where(baseWhereClause),
            db
                .select()
                .from(customers)
                .where(cursorWhereClause)
                .orderBy(sql`lower(${customers.name})`, asc(customers.id))
                .limit(PAGE_SIZE + 1),
        ]);

        const hasMore = pageRows.length > PAGE_SIZE;
        const data = pageRows.slice(0, PAGE_SIZE);
        const lastCustomer = data[data.length - 1];
        const nextCursor = hasMore && lastCustomer
            ? encodeCursor({ name: lastCustomer.name.toLowerCase(), id: lastCustomer.id })
            : null;

        const response: CustomersPageResponse = {
            data,
            nextCursor,
            totalCount: Number(countResult[0]?.count ?? 0),
        };

        return NextResponse.json(response);
    } catch (error) {
        console.error("Customers API Error:", error);
        return NextResponse.json({ error: "Failed to fetch customers" }, { status: 500 });
    }
}

